// prefsGlyphThumb returns a squircle avatar preview at the given px size.
// Matches the spec "shown here at the actual pixel sizes" requirement.
func prefsGlyphThumb(px int) string {
	s := strconv.Itoa(px)
	r := strconv.Itoa(px / 4) // squircle radius ~25%
	return `<span style="display:flex;align-items:center;justify-content:center;width:` + s + `px;height:` + s + `px;border-radius:` + r + `px;background:linear-gradient(135deg,currentColor,currentColor);opacity:.35;flex-shrink:0;"></span>`
}

// prefsGlyphFont returns an "Aa" specimen span rendered in the given font stack.
func prefsGlyphFont(stack string) string {
	return `<span style="font-family:` + stack + `;font-weight:700;font-size:17px;line-height:1;letter-spacing:0;">Stillwater</span>`
}

// prefsGlyphMono returns a timestamp + id specimen span in the given mono font stack.
func prefsGlyphMono(stack string) string {
	return `<span style="font-family:` + stack + `;font-weight:600;font-size:11px;line-height:1.4;text-align:center;letter-spacing:0;">` +
		`<span style="display:block;">14:02:37</span>` +
		`<span style="display:block;opacity:.6;font-size:10px;">a74b1b7f</span>` +
		`</span>`
}

