// fontSizeToStop maps a stored font_size value to its 0-4 slider index.
// Unknown values fall back to 1 (medium).
func fontSizeToStop(v string) int {
	switch v {
	case "small":
		return 0
	case "medium":
		return 1
	case "large":
		return 2
	case "x-large":
		return 3
	case "xx-large":
		return 4
	default:
		return 1
	}
}

// fontSizeStopKey maps a font_size value to its i18n label key. Unknown values
// fall back to medium, mirroring fontSizeToStop.
func fontSizeStopKey(v string) string {
	switch v {
	case "small", "medium", "large":
		return "prefs.font_size." + v
	case "x-large":
		return "prefs.font_size.x_large"
	case "xx-large":
		return "prefs.font_size.xx_large"
	default:
		return "prefs.font_size.medium"
	}
}

// fontSizeStopName returns the localized display label for a font_size value.
// Used for aria-valuetext and the live value badge.
func fontSizeStopName(ctx context.Context, v string) string {
	return t(ctx, fontSizeStopKey(v))
}

// fontSizeStopNamesAttr returns the five localized stop labels, pipe-joined in
// stop order, for the slider's data-stop-names attribute. prefs-drawer.js reads
// it so the client-side live label and aria-valuetext stay localized instead of
// duplicating English strings in JS.
func fontSizeStopNamesAttr(ctx context.Context) string {
	stops := []string{"small", "medium", "large", "x-large", "xx-large"}
	names := make([]string, len(stops))
	for i, s := range stops {
		names[i] = t(ctx, fontSizeStopKey(s))
	}
	return strings.Join(names, "|")
}

// prefsGlyphLetterSpacing returns a "TYPE" specimen previewing the given
// letter-spacing. The spacing is a STATIC inline literal (immune to the
// user's current letter_spacing pref, which would otherwise re-track the
// specimens and defeat the comparison), and the container has a FIXED width
// shared by all three tiles so each option's specimen shows its specific
// tracking without the tiles themselves changing size (maintainer call
// 2026-06-09).
func prefsGlyphLetterSpacing(em string) string {
	return `<span style="display:inline-block;width:3.75rem;overflow:hidden;text-align:center;font-weight:700;font-size:13px;letter-spacing:` + em + `;">TYPE</span>`
}

